    86    struct PerAddressActiveListenerDetails {
    87      // Strong pointer to the listener, whether TCP, UDP, QUIC, etc.
    88      Network::ConnectionHandler::ActiveListenerPtr listener_;
    89      Network::Address::InstanceConstSharedPtr address_;
    90      uint64_t listener_tag_;
    91
    92      absl::variant<absl::monostate, std::reference_wrapper<ActiveTcpListener>,
    93                    std::reference_wrapper<Network::UdpListenerCallbacks>,
    94                    std::reference_wrapper<Network::InternalListener>>
    95          typed_listener_;
    96
    97      // Helpers for accessing the data in the variant for cleaner code.
    98      ActiveTcpListenerOptRef tcpListener();
    99      UdpListenerCallbacksOptRef udpListener();
   100      Network::InternalListenerOptRef internalListener();
   101    };
   102
   103    struct ActiveListenerDetails {
   104      std::vector<std::shared_ptr<PerAddressActiveListenerDetails>> per_address_details_list_;
   105
   106      using ListenerMethodFn = std::function<void(Network::ConnectionHandler::ActiveListener&)>;
   107
   108      /**
   109       * A helper to execute specific method on each PerAddressActiveListenerDetails item.
   110       */
   111      void invokeListenerMethod(ListenerMethodFn fn) {
   112        std::for_each(per_address_details_list_.begin(), per_address_details_list_.end(),
   113                      [&fn](std::shared_ptr<PerAddressActiveListenerDetails>& details) {
   114                        fn(*details->listener_);
   115                      });
   116      }
   117
   118      /**
   119       * Add an ActiveListener into the list.
   120       */
   121      template <class ActiveListener>
   122      void addActiveListener(Network::ListenerConfig& config,
   123                             const Network::Address::InstanceConstSharedPtr& address,
   124                             UnitFloat& listener_reject_fraction, bool disable_listeners,
   125                             ActiveListener&& listener, OptRef<OverloadManager> overload_manager) {
   126        auto per_address_details = std::make_shared<PerAddressActiveListenerDetails>();
   127        per_address_details->typed_listener_ = *listener;
   128        per_address_details->listener_ = std::move(listener);
   129        per_address_details->address_ = address;
   130        if (disable_listeners) {
   131          per_address_details->listener_->pauseListening();
   132        }
   133        if (auto* listener = per_address_details->listener_->listener(); listener != nullptr) {
   134          listener->setRejectFraction(listener_reject_fraction);
   135          if (overload_manager) {
   136            listener->configureLoadShedPoints(overload_manager.value());
   137          }
   138        }
   139        per_address_details->listener_tag_ = config.listenerTag();
   140        per_address_details_list_.emplace_back(per_address_details);
   141      }
   142    };
   143
   144    using ActiveListenerDetailsOptRef = absl::optional<std::reference_wrapper<ActiveListenerDetails>>;
   145    ActiveListenerDetailsOptRef findActiveListenerByTag(uint64_t listener_tag);
   146
   147    using PerAddressActiveListenerDetailsOptRef =
   148        absl::optional<std::reference_wrapper<PerAddressActiveListenerDetails>>;
   149    PerAddressActiveListenerDetailsOptRef
   150    findPerAddressActiveListenerDetails(const ActiveListenerDetailsOptRef active_listener_details,
   151                                        const Network::Address::Instance& address);
   152
   153    // This has a value on worker threads, and no value on the main thread.
   154    const absl::optional<uint32_t> worker_index_;
   155    Event::Dispatcher& dispatcher_;
   156    OptRef<OverloadManager> overload_manager_;
   157    OptRef<OverloadManager> null_overload_manager_;
   158    const std::string per_handler_stat_prefix_;
   159    // Declare before its users ActiveListenerDetails.
   160    std::atomic<uint64_t> num_handler_connections_{};
   161    absl::flat_hash_map<uint64_t, std::unique_ptr<ActiveListenerDetails>> listener_map_by_tag_;
   162    absl::flat_hash_map<std::string, std::shared_ptr<PerAddressActiveListenerDetails>>
   163        tcp_listener_map_by_address_;
   164    absl::flat_hash_map<std::string, std::shared_ptr<PerAddressActiveListenerDetails>>
   165        internal_listener_map_by_address_;
   166
   167    bool disable_listeners_;
   168    UnitFloat listener_reject_fraction_{UnitFloat::min()};
   169  };
