   166  void ActiveTcpListener::post(Network::ConnectionSocketPtr&& socket) {
   167    // It is not possible to capture a unique_ptr because the post() API copies the lambda, so we must
   168    // bundle the socket inside a shared_ptr that can be captured.
   169    // TODO(mattklein123): It may be possible to change the post() API such that the lambda is only
   170    // moved, but this is non-trivial and needs investigation.
   171    RebalancedSocketSharedPtr socket_to_rebalance = std::make_shared<RebalancedSocket>();
   172    socket_to_rebalance->socket = std::move(socket);
   173
   174    dispatcher().post([socket_to_rebalance, address = listen_address_, tag = config_->listenerTag(),
   175                       &tcp_conn_handler = tcp_conn_handler_,
   176                       handoff = config_->handOffRestoredDestinationConnections()]() {
   177      auto balanced_handler = tcp_conn_handler.getBalancedHandlerByTag(tag, *address);
   178      if (balanced_handler.has_value()) {
   179        balanced_handler->get().onAcceptWorker(std::move(socket_to_rebalance->socket), handoff, true);
   180        return;
   181      }
   182    });
   183  }
