   715	void UpstreamRequest::readDisableOrDefer(bool disable) {
   716	  if (disable) {
   717	    // See comments on deferred_read_disabling_count_ for when we do and don't defer.
   718	    if (parent_.downstreamResponseStarted()) {
   719	      // The downstream connection is overrun. Pause reads from upstream.
   720	      // If there are multiple calls to readDisable either the codec (H2) or the
   721	      // underlying Network::Connection (H1) will handle reference counting.
   722	      parent_.cluster()->trafficStats()->upstream_flow_control_paused_reading_total_.inc();
   723	      upstream_->readDisable(disable);
