   294	ConnectionPool::Cancellable* ConnPoolImplBase::newStreamImpl(AttachContext& context,
   295	                                                             bool can_send_early_data) {
   296	  ASSERT(!is_draining_for_deletion_);
   297	  ASSERT(!deferred_deleting_);
   298	  assertCapacityCountsAreCorrect();
   299	
   300	  if (!ready_clients_.empty()) {
   301	    ActiveClient& client = *ready_clients_.front();
   302	    ENVOY_CONN_LOG(debug, "using existing fully connected connection", client);
   303	    attachStreamToClient(client, context);
   304	    // Even if there's a ready client, we may want to preconnect to handle the next incoming stream.
   305	    tryCreateNewConnections();
   306	    return nullptr;
   307	  }
   308	
   309	  if (can_send_early_data && !early_data_clients_.empty()) {
   310	    ActiveClient& client = *early_data_clients_.front();
   311	    ENVOY_CONN_LOG(debug, "using existing early data ready connection", client);
   312	    attachStreamToClient(client, context);
   313	    // Even if there's an available client, we may want to preconnect to handle the next
   314	    // incoming stream.
   315	    tryCreateNewConnections();
   316	    return nullptr;
   317	  }
   318	
   319	  if (!host_->cluster().resourceManager(priority_).pendingRequests().canCreate()) {
   320	    ENVOY_LOG(debug, "max pending streams overflow");
   321	    onPoolFailure(nullptr, absl::string_view(), ConnectionPool::PoolFailureReason::Overflow,
   322	                  context);
   323	    host_->cluster().trafficStats()->upstream_rq_pending_overflow_.inc();
   324	    return nullptr;
   325	  }
   326	
   327	  ConnectionPool::Cancellable* pending = newPendingStream(context, can_send_early_data);
   328	  ENVOY_LOG(debug, "trying to create new connection");
   329	  ENVOY_LOG(trace, fmt::format("{}", *this));
   330	
   331	  auto old_capacity = connecting_stream_capacity_;
   332	  // This must come after newPendingStream() because this function uses the
   333	  // length of pending_streams_ to determine if a new connection is needed.
   334	  const ConnectionResult result = tryCreateNewConnections();
   335	  // If there is not enough connecting capacity, the only reason to not
   336	  // increase capacity is if the connection limits are exceeded.
   337	  ENVOY_BUG(pending_streams_.size() <= connecting_stream_capacity_ ||
   338	                connecting_stream_capacity_ > old_capacity ||
   339	                (result == ConnectionResult::NoConnectionRateLimited ||
   340	                 result == ConnectionResult::FailedToCreateConnection),
   341	            fmt::format("Failed to create expected connection: {}", *this));
   342	  if (result == ConnectionResult::FailedToCreateConnection) {
   343	    // This currently only happens for HTTP/3 if secrets aren't yet loaded.
   344	    // Trigger connection failure.
   345	    pending->cancel(Envoy::ConnectionPool::CancelPolicy::CloseExcess);
   346	    onPoolFailure(nullptr, absl::string_view(),
   347	                  ConnectionPool::PoolFailureReason::LocalConnectionFailure, context);
   348	    return nullptr;
   349	  }
   350	  return pending;
   351	}
