   581	    const ServerNamesMap& server_names_map, const Network::ConnectionSocket& socket) const {
   582	  ASSERT(absl::AsciiStrToLower(socket.requestedServerName()) == socket.requestedServerName());
   583	  const std::string server_name(socket.requestedServerName());
