   585	  // Match on exact server name, i.e. "www.example.com" for "www.example.com".
   586	  const auto server_name_exact_match = server_names_map.find(server_name);
   587	  if (server_name_exact_match != server_names_map.end()) {
   588	    return findFilterChainForTransportProtocol(server_name_exact_match->second, socket);
