   590	
   591	  // Match on all wildcard domains, i.e. ".example.com" and ".com" for "www.example.com".
   592	  size_t pos = server_name.find('.', 1);
   593	  while (pos < server_name.size() - 1 && pos != std::string::npos) {
   594	    const std::string wildcard = server_name.substr(pos);
   595	    const auto server_name_wildcard_match = server_names_map.find(wildcard);
   596	    if (server_name_wildcard_match != server_names_map.end()) {
   597	      return findFilterChainForTransportProtocol(server_name_wildcard_match->second, socket);
   598	    }
   599	    pos = server_name.find('.', pos + 1);
   600	  }
   601	
   602	  // Match on a filter chain without server name requirements.
   603	  const auto server_name_catchall_match = server_names_map.find(EMPTY_STRING);
   604	  if (server_name_catchall_match != server_names_map.end()) {
   605	    return findFilterChainForTransportProtocol(server_name_catchall_match->second, socket);
   606	  }
   607	
   608	  return nullptr;
