   203	void ConnPoolImplBase::attachStreamToClient(Envoy::ConnectionPool::ActiveClient& client,
   204	                                            AttachContext& context) {
   205	  ASSERT(client.readyForStream());
   206	
   207	  Upstream::ClusterTrafficStats& traffic_stats = *host_->cluster().trafficStats();
   208	  if (client.state() == Envoy::ConnectionPool::ActiveClient::State::ReadyForEarlyData) {
   209	    traffic_stats.upstream_rq_0rtt_.inc();
   210	  }
   211	
   212	  if (enforceMaxRequests() && !host_->cluster().resourceManager(priority_).requests().canCreate()) {
   213	    ENVOY_LOG(debug, "max streams overflow");
   214	    onPoolFailure(client.real_host_description_, absl::string_view(),
   215	                  ConnectionPool::PoolFailureReason::Overflow, context);
   216	    traffic_stats.upstream_rq_pending_overflow_.inc();
   217	    return;
   218	  }
   219	  ENVOY_CONN_LOG(debug, "creating stream", client);
   220	
   221	  // Latch capacity before updating remaining streams.
   222	  uint64_t capacity = client.currentUnusedCapacity();
   223	  client.remaining_streams_--;
   224	  if (client.remaining_streams_ == 0) {
   225	    ENVOY_CONN_LOG(debug, "maximum streams per connection, start draining", client);
   226	    traffic_stats.upstream_cx_max_requests_.inc();
   227	    transitionActiveClientState(client, Envoy::ConnectionPool::ActiveClient::State::Draining);
   228	  } else if (capacity == 1) {
   229	    // As soon as the new stream is created, the client will be maxed out.
   230	    transitionActiveClientState(client, Envoy::ConnectionPool::ActiveClient::State::Busy);
   231	  }
   232	
   233	  // Decrement the capacity, as there's one less stream available for serving.
   234	  // For HTTP/3, the capacity is updated in newStreamEncoder.
   235	  if (trackStreamCapacity()) {
   236	    decrConnectingAndConnectedStreamCapacity(1, client);
   237	  }
   238	  // Track the new active stream.
   239	  state_.incrActiveStreams(1);
   240	  num_active_streams_++;
   241	  host_->stats().rq_total_.inc();
   242	  host_->stats().rq_active_.inc();
   243	  traffic_stats.upstream_rq_total_.inc();
   244	  traffic_stats.upstream_rq_active_.inc();
   245	  host_->cluster().resourceManager(priority_).requests().inc();
   246	
   247	  onPoolReady(client, context);
