   250	void ConnPoolImplBase::onStreamClosed(Envoy::ConnectionPool::ActiveClient& client,
   251	                                      bool delay_attaching_stream) {
   252	  ENVOY_CONN_LOG(
   253	      debug, "destroying stream: {} active remaining, readyForStream {}, currentUnusedCapacity {}",
   254	      client, client.numActiveStreams(), client.readyForStream(), client.currentUnusedCapacity());
   255	  ASSERT(num_active_streams_ > 0);
   256	  state_.decrActiveStreams(1);
   257	  num_active_streams_--;
   258	  host_->stats().rq_active_.dec();
   259	  host_->cluster().trafficStats()->upstream_rq_active_.dec();
   260	  host_->cluster().resourceManager(priority_).requests().dec();
   261	  // We don't update the capacity for HTTP/3 as the stream count should only
   262	  // increase when a MAX_STREAMS frame is received.
   263	  if (trackStreamCapacity()) {
   264	    // If the effective client capacity was limited by concurrency, increase connecting capacity.
   265	    bool limited_by_concurrency =
   266	        client.remaining_streams_ > client.concurrent_stream_limit_ - client.numActiveStreams() - 1;
   267	    // The capacity calculated by concurrency could be negative if a SETTINGS frame lowered the
   268	    // number of allowed streams. In this case, effective client capacity was still limited by
   269	    // concurrency, compare client.concurrent_stream_limit_ and client.numActiveStreams() directly
   270	    // to avoid overflow.
   271	    bool negative_capacity = client.concurrent_stream_limit_ < client.numActiveStreams() + 1;
   272	    if (negative_capacity || limited_by_concurrency) {
   273	      incrConnectingAndConnectedStreamCapacity(1, client);
   274	    }
   275	  }
   276	  if (client.state() == ActiveClient::State::Draining && client.numActiveStreams() == 0) {
   277	    // Close out the draining client if we no longer have active streams.
   278	    client.close();
   279	  } else if (client.state() == ActiveClient::State::Busy && client.currentUnusedCapacity() > 0) {
   280	    if (!client.hasHandshakeCompleted()) {
   281	      transitionActiveClientState(client, ActiveClient::State::ReadyForEarlyData);
   282	      if (!delay_attaching_stream) {
   283	        onUpstreamReadyForEarlyData(client);
   284	      }
   285	    } else {
   286	      transitionActiveClientState(client, ActiveClient::State::Ready);
   287	      if (!delay_attaching_stream) {
   288	        onUpstreamReady();
   289	      }
   290	    }
   291	  }
   292	}
