```cpp
HostSelectionResponse ClusterEntry::chooseHost(LoadBalancerContext* context) {
  // 1. Override host check (x-envoy-upstream-rq-per-try-timeout-ms, etc.)
  auto cross_priority_host_map = priority_set_.crossPriorityHostMap();
  HostConstSharedPtr host = HostUtility::selectOverrideHost(
      cross_priority_host_map.get(), override_host_statuses_, context);
  if (host != nullptr) return {std::move(host)};

  // 2. Normal LB selection
  if (HostUtility::allowLBChooseHost(context)) {
    Upstream::HostSelectionResponse host_selection = lb_->chooseHost(context);
    if (host_selection.host || host_selection.cancelable) return host_selection;
    cluster_info_->trafficStats()->upstream_cx_none_healthy_.inc();
  }
  return {nullptr};
}
