void Filter::onUpstreamHeaders(uint64_t response_code,
                               Http::ResponseHeaderMapPtr&& headers,
                               UpstreamRequest& upstream_request, bool end_stream) {
  modify_headers_(*headers);  // append cluster/host debug headers if configured

  // gRPC status → HTTP status conversion for outlier detection
  upstream_request.upstreamHost()->outlierDetector().putHttpResponseCode(response_code);

  // Retry logic
  if (retry_state_) {
    const RetryStatus retry_status = retry_state_->shouldRetryHeaders(
        *headers, *downstream_headers_,
        [this, ...](bool disable_early_data) -> void {
          doRetry(...);
        });
    if (retry_status == RetryStatus::Yes) {
      upstream_request.resetStream();
      // Remove this upstream request, retry will create a new one
      return;
    }
  }

  // Internal redirect (3xx handling)
  if (route_entry_->internalRedirectPolicy().enabled() && setupRedirect(*headers)) {
    return;
  }

  // Finalize response headers (add/remove configured headers)
  route_entry_->finalizeResponseHeaders(*headers, callbacks_->streamInfo());

  downstream_response_started_ = true;
  callbacks_->streamInfo().setUpstreamInfo(upstream_request.streamInfo().upstreamInfo());

  // Forward to downstream encoder filter chain
  callbacks_->encodeHeaders(std::move(headers), end_stream,
                            StreamInfo::ResponseCodeDetails::get().ViaUpstream);
}
