```cpp
void FilterManager::encodeHeaders(ActiveStreamEncoderFilter* filter,
                                  ResponseHeaderMap& headers, bool end_stream) {
  StreamEncoderFilters::Iterator entry =
      commonEncodePrefix(filter, end_stream, FilterIterationStartState::AlwaysStartFromNext);

  for (; entry != encoder_filters_.end(); entry++) {
    FilterHeadersStatus status = (*entry)->handle_->encodeHeaders(headers, (*entry)->end_stream_);
    const auto continue_iteration =
        (*entry)->commonHandleAfterHeadersCallback(status, end_stream);
    if (!continue_iteration) {
      maybeContinueEncoding(continue_data_entry);
      return;
    }
  }

  // Validate required response headers (e.g., :status)
  const auto status = HeaderUtility::checkRequiredResponseHeaders(headers);
  if (!status.ok()) {
    sendLocalReply(Http::Code::BadGateway, status.message(), ...);
    return;
  }

  // Write to downstream codec
  filter_manager_callbacks_.encodeHeaders(headers, modified_end_stream);
  maybeEndEncode(modified_end_stream);
}
```

Encoder filters iterate in **reverse order** (C→B→A). After all encoder filters pass, `filter_manager_callbacks_.encodeHeaders()` writes the response headers to the downstream HTTP codec, which serializes them to the downstream TCP connection.

