```cpp
bool RouteEntryImplBase::matchRoute(const Http::RequestHeaderMap& headers,
                                    const StreamInfo::StreamInfo& stream_info,
                                    uint64_t random_value) const {
  bool matches = true;
  matches &= evaluateRuntimeMatch(random_value);   // runtime fraction
  matches &= Grpc::Common::isGrpcRequestHeaders(headers);  // if grpc_only
  matches &= Http::HeaderUtility::matchHeaders(headers, config_headers_);  // header matchers
  matches &= ConfigUtility::matchQueryParams(query_parameters, config_query_parameters_);
  matches &= evaluateTlsContextMatch(stream_info);  // TLS metadata
  matches &= m.match(stream_info.dynamicMetadata());  // dynamic metadata
  matches &= m->match(stream_info.filterState());     // filter state
