### `HostImplBase::createConnection()` — upstream_impl.cc L582

Called by `instantiateActiveClient()` in the connection pool:

```cpp
Host::CreateConnectionData HostImplBase::createConnection(
    Event::Dispatcher& dispatcher, const ClusterInfo& cluster,
    const Network::Address::InstanceConstSharedPtr& address,
    const SharedConstAddressVector& address_list_or_null,
    Network::UpstreamTransportSocketFactory& socket_factory,
    const Network::ConnectionSocket::OptionsSharedPtr& options,
    Network::TransportSocketOptionsConstSharedPtr transport_socket_options,
    HostDescriptionConstSharedPtr host) {

  auto source_address_selector = cluster.getUpstreamLocalAddressSelector();

  Network::ClientConnectionPtr connection;

  if (proxy_address.has_value()) {
    // HTTP/1.1 CONNECT proxy: connect to proxy, not to upstream host
    connection = dispatcher.createClientConnection(proxy_address.value(), ...);

  } else if (address_list_or_null != nullptr && address_list_or_null->size() > 1) {
    // Happy Eyeballs (RFC 8305): parallel IPv4/IPv6 connection attempts
    connection = std::make_unique<Network::HappyEyeballsConnectionImpl>(
        dispatcher, *address_list_or_null, source_address_selector,
        socket_factory, transport_socket_options, host, options, happy_eyeballs_config);

  } else {
    // Standard single-address connection
    auto upstream_local_address =
        source_address_selector->getUpstreamLocalAddress(address, options);
    connection = dispatcher.createClientConnection(
        address,
        upstream_local_address.address_,
        socket_factory.createTransportSocket(transport_socket_options, host),
        upstream_local_address.socket_options_,
        transport_socket_options);
  }

  connection->setBufferLimits(cluster.perConnectionBufferLimitBytes());
  cluster.createNetworkFilterChain(*connection);  // upstream network filters
  return {std::move(connection), std::move(host)};
}
```

**Three connection paths:**
1. **HTTP/1.1 proxy:** TCP connection to proxy address; upstream address sent in CONNECT request.
2. **Happy Eyeballs:** `HappyEyeballsConnectionImpl` attempts IPv6 first, then IPv4 after a delay (default 300ms), uses whichever connects first.
3. **Standard:** `ClientConnectionImpl` with a single resolved address.

### `ClientConnectionImpl::connect()` — connection_impl.cc L1090

```cpp
void ClientConnectionImpl::connect() {
  const Api::SysCallIntResult result = transport_socket_->connect(*socket_);
  stream_info_.upstreamInfo()->upstreamTiming().onUpstreamConnectStart(
      dispatcher_.timeSource());

  if (result.return_value_ == 0) {
    // Immediate connect (loopback, Unix socket)
    ASSERT(connecting_);
    return;
  }

  if (result.errno_ == SOCKET_ERROR_IN_PROGRESS) {
    // Normal async connect: EINPROGRESS
    ASSERT(connecting_);
    // libevent will fire Write event when connect() completes
  } else {
    // Immediate error
    immediate_error_event_ = ConnectionEvent::RemoteClose;
    ioHandle().activateFileEvents(Event::FileReadyType::Write);
  }
}
```

For TLS, `transport_socket_->connect()` calls the underlying `RawBufferSocket::connect()` which issues the kernel `connect()` syscall. The TLS handshake begins after the TCP connection is established (on the Write event).

